import React from "react";
import { BrowserRouter as Router, Route, Routes } from "react-router-dom";
import Navbar from "./components/NavBar";
import Hero from "./components/Hero";
import About from "./components/About";
import Contact from "./components/Contact";
import Footer from "./components/Footer";
import WebsiteDesign from "./components/WebsiteDesign";
import FigmaDesign from "./components/FigmaDesign";
import DashboardDesign from "./components/DashboardDesign";
import "./App.css";

const App = () => {
  return (
    <Router>
      <div className="App">
        <Navbar />
        <Routes>
          <Route path="/" element={<Hero />} />
          <Route path="/about" element={<About />} />
          <Route path="/contact" element={<Contact />} />
          <Route path="/website-design" element={<WebsiteDesign />} />
          <Route path="/figma-design" element={<FigmaDesign />} />
          <Route path="/dashboard-design" element={<DashboardDesign />} />
        </Routes>
        <Footer />
      </div>
    </Router>
  );
};

export default App;
